func SaveAuthProfile(name, method string, ref auth.TokenRef, values map[string]string) (*Profile, error) {
	if strings.TrimSpace(name) == "" {
		return nil, fmt.Errorf("profile name is required")
	}
	if method == "" {
		method = auth.MethodSFFallthrough
	}
	s, err := loadProfileStore()
	if err != nil {
		return nil, err
	}
	now := time.Now().UTC()
	profile := s.Profiles[name]
	if profile.Name == "" {
		profile.Name = name
	}
	if profile.Values == nil {
		profile.Values = map[string]string{}
	}
	for k, v := range values {
		profile.Values[k] = v
	}
	profile.AuthMethod = method
	profile.TokenRef = ref
	if profile.CreatedAt.IsZero() {
		profile.CreatedAt = now
	}
	profile.LastUsedAt = now
	s.Profiles[name] = profile
	if err := saveProfileStore(s); err != nil {
		return nil, err
	}
	return &profile, nil
}

func TouchProfile(name string) error {
	if name == "" {
		return nil
	}
	s, err := loadProfileStore()
	if err != nil {
		return err
	}
	profile, ok := s.Profiles[name]
	if !ok {
		return nil
	}
	profile.LastUsedAt = time.Now().UTC()
	s.Profiles[name] = profile
	return saveProfileStore(s)
}

func DeleteAuthProfile(name string) error {
	s, err := loadProfileStore()
	if err != nil {
		return err
	}
	profile, ok := s.Profiles[name]
	if !ok {
		return fmt.Errorf("profile %q not found", name)
	}
	if profile.TokenRef.Service != "" || profile.TokenRef.Key != "" {
		_ = auth.DeleteStoredToken(profile.TokenRef)
	}
	delete(s.Profiles, name)
	if err := saveProfileStore(s); err != nil {
		return err
	}
	active, _ := ActiveProfile()
	if active == name {
		return SetActiveProfile("")
	}
	return nil
}

